#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding predicting-risk-of-cardiovascular-disease-events (15 tables)..."

cargo loco generate scaffold patient \
    full_name:text! \
    date_of_birth:text! \
    nhs_number:text! \
    address:text! \
    telephone:text! \
    email:text! \
    gp_name:text! \
    gp_practice:text! \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:text! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    age:int \
    sex:text! \
    ethnicity:text! \
    height_cm:double \
    weight_kg:double \
    zip_code:text! \
    --htmx

cargo loco generate scaffold assessment_blood_pressure \
    assessment:references \
    systolic_bp:double \
    diastolic_bp:double \
    on_antihypertensive:text! \
    number_of_bp_medications:int \
    bp_at_target:text! \
    --htmx

cargo loco generate scaffold assessment_cholesterol_lipids \
    assessment:references \
    total_cholesterol:double \
    hdl_cholesterol:double \
    ldl_cholesterol:double \
    triglycerides:double \
    non_hdl_cholesterol:double \
    on_statin:text! \
    statin_name:text! \
    --htmx

cargo loco generate scaffold assessment_metabolic_health \
    assessment:references \
    has_diabetes:text! \
    diabetes_type:text! \
    hba1c_value:double \
    hba1c_unit:text! \
    fasting_glucose:double \
    bmi:double \
    waist_circumference_cm:double \
    --htmx

cargo loco generate scaffold assessment_renal_function \
    assessment:references \
    egfr:double \
    creatinine:double \
    urine_acr:double \
    ckd_stage:text! \
    --htmx

cargo loco generate scaffold assessment_smoking_history \
    assessment:references \
    smoking_status:text! \
    cigarettes_per_day:int \
    years_smoked:int \
    years_since_quit:int \
    --htmx

cargo loco generate scaffold assessment_medical_history \
    assessment:references \
    has_known_cvd:text! \
    previous_mi:text! \
    previous_stroke:text! \
    heart_failure:text! \
    peripheral_arterial_disease:text! \
    atrial_fibrillation:text! \
    family_cvd_history:text! \
    family_cvd_details:text! \
    --htmx

cargo loco generate scaffold assessment_current_medications \
    assessment:references \
    on_antihypertensive_detail:text! \
    on_statin_detail:text! \
    on_aspirin:text! \
    on_anticoagulant:text! \
    on_diabetes_medication:text! \
    other_medications:text! \
    --htmx

cargo loco generate scaffold assessment_review_calculate \
    assessment:references \
    model_type:text! \
    clinician_name:text! \
    review_date:text! \
    clinical_notes:text! \
    --htmx

cargo loco generate scaffold pvt_rule \
    category:text! \
    description:text! \
    risk_level:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    risk_category:text! \
    ten_year_risk_percent:double! \
    thirty_year_risk_percent:double! \
    risk_category_override:text \
    override_reason:text! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    pvt_rule:references \
    rule_category:text! \
    rule_description:text! \
    rule_risk_level:text! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:text! \
    category:text! \
    message:text! \
    priority:text! \
    --htmx

echo "Done."
